const rows = $input.all();
if (rows.length === 0 || !rows[0].json.subreddit_name) {
  return [{ json: { text: 'No monitored subreddits or posts found.', post_ids: [], ref_map: {} } }];
}

const subreddits = {};
const postIds = new Set();

rows.forEach(row => {
  const data = row.json;
  const subName = data.subreddit_name;
  if (!subreddits[subName]) {
    subreddits[subName] = { active: data.subreddit_active, posts: {} };
  }
  if (data.post_id) {
    postIds.add(data.post_id);
    if (!subreddits[subName].posts[data.post_id]) {
      subreddits[subName].posts[data.post_id] = {
        title: data.post_title,
        content: data.post_content,
        author: data.post_author,
        url: data.post_url,
        created_at: data.post_created_at,
        comments: []
      };
    }
    if (data.comment_id) {
      subreddits[subName].posts[data.post_id].comments.push({
        author: data.comment_author,
        content: data.comment_content,
        created_at: data.comment_created_at
      });
    }
  }
});

// Assign sequential numbers to every post for the LLM to reference
const refMap = {};
let refCounter = 1;

let text = 'Posts to summarize (each has an id number):\n\n';

for (const [subName, subInfo] of Object.entries(subreddits)) {
  const postsList = Object.values(subInfo.posts);
  if (postsList.length === 0) continue;

  text += `Subreddit: r/${subName}\n`;
  postsList.forEach(post => {
    const refId = refCounter++;
    refMap[String(refId)] = { title: post.title || 'Post', url: post.url || '' };

    text += `  id:${refId} | ${post.title || 'No Title'} (by u/${post.author || 'unknown'})\n`;
    text += `  Content: ${(post.content || '').substring(0, 500)}\n`;
    if (post.comments.length > 0) {
      text += `  Top comments:\n`;
      post.comments.slice(0, 3).forEach(comment => {
        text += `    - u/${comment.author || 'unknown'}: ${(comment.content || '').substring(0, 200)}\n`;
      });
    }
    text += '\n';
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/agents/bella.md', 'utf8');
} catch (e) {
  persona = 'Warm, charming Italian secretary named Bella.';
}

return [{ json: { text, post_ids: Array.from(postIds), ref_map: refMap, bella_persona: persona } }];

const raw = $input.first().json.content || $input.first().json.response || '';
const refMap = $('Format Posts for LLM').first().json.ref_map || {};

let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  try {
    const cleanedStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
    parsed = JSON.parse(cleanedStr);
  } catch (err) {
    return [{ json: { response: raw } }];
  }
}

const greeting = parsed.greeting || '';
const signoff = parsed.signoff || '';
const insights = Array.isArray(parsed.insights) ? parsed.insights : [];

let msg = '';
if (greeting) msg += `${greeting}\n\n`;
msg += '✨ *Key Insights & Opportunities*\n\n';

insights.forEach(insight => {
  const topic = insight.topic || 'Insight';
  const summary = insight.summary || '';
  const postIds = Array.isArray(insight.post_ids) ? insight.post_ids : [];

  const links = postIds
    .map(id => {
      const ref = refMap[String(id)];
      if (!ref || !ref.url) return null;
      return `<${ref.url}|${ref.title}>`;
    })
    .filter(Boolean);

  const linkStr = links.length > 0 ? ' ' + links.join(' ') : '';
  msg += `• *${topic}:* ${summary}${linkStr}\n`;
});

if (signoff) msg += `\n${signoff}`;

return [{ json: { response: msg } }];
